function GameTimer() {
  const [seconds, setSeconds] = React.useState(60);
  const [timeLeft, setTimeLeft] = React.useState(60);
  const [running, setRunning] = React.useState(false);
  const [buzzed, setBuzzed] = React.useState(false);

  React.useEffect(() => {
    if (!running) return;
    const interval = setInterval(() => {
      setTimeLeft((t) => {
        if (t <= 1) {
          setRunning(false);
          setBuzzed(true);
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [running]);

  const reset = () => {
    setRunning(false);
    setBuzzed(false);
    setTimeLeft(seconds);
  };

  const fmt = (s) => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: buzzed ? '#fef2f2' : '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b', alignItems: 'center', justifyContent: 'center' }}>
      <h2 style={{ margin: '0 0 16px', fontSize: 18 }}>Game Timer</h2>
      <div style={{ fontSize: 56, fontWeight: 800, color: buzzed ? '#dc2626' : timeLeft <= 10 ? '#ea580c' : '#059669', marginBottom: 16, fontVariantNumeric: 'tabular-nums' }}>
        {fmt(timeLeft)}
      </div>
      {buzzed && <div style={{ fontSize: 20, fontWeight: 700, color: '#dc2626', marginBottom: 16 }}>Time’s Up!</div>}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <button onClick={() => setRunning(!running)} style={{ padding: '10px 20px', borderRadius: 8, border: 'none', background: running ? '#dc2626' : '#059669', color: '#fff', fontSize: 15, fontWeight: 600, cursor: 'pointer' }}>{running ? 'Pause' : 'Start'}</button>
        <button onClick={reset} style={{ padding: '10px 20px', borderRadius: 8, border: '1px solid #cbd5e1', background: '#fff', color: '#1e293b', fontSize: 15, fontWeight: 600, cursor: 'pointer' }}>Reset</button>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
        <label style={{ fontSize: 13, fontWeight: 500 }}>Seconds:</label>
        <input type="number" value={seconds} onChange={e => { const v = Number(e.target.value); setSeconds(v); setTimeLeft(v); setBuzzed(false); }} style={{ width: 70, padding: 6, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14, textAlign: 'center' }} />
      </div>
    </div>
  );
}
render(<GameTimer/>);
